45: func newGrpcPlugin(descriptor PluginDescriptor, logger log.Logger, env func() []string) *grpcPlugin {
46: 	return &grpcPlugin{
47: 		descriptor: descriptor,
48: 		logger:     logger,
49: 		clientFactory: func() *plugin.Client {
50: 			return plugin.NewClient(newClientConfig(descriptor.executablePath, descriptor.executableArgs, env(), descriptor.skipHostEnvVars, logger, descriptor.versionedPlugins))
51: 		},
52: 		state: pluginStateNotStarted,
53: 	}
54: }
