64: func (p *grpcPlugin) Start(_ context.Context) error {
65: 	p.mutex.Lock()
66: 	defer p.mutex.Unlock()
67: 
68: 	p.state = pluginStateStartInit
69: 
70: 	p.client = p.clientFactory()
71: 	rpcClient, err := p.client.Client()
72: 	if err != nil {
73: 		p.state = pluginStateStartFail
74: 		return err
75: 	}
76: 
77: 	if p.client.NegotiatedVersion() < 2 {
78: 		p.state = pluginStateStartFail
79: 		return errors.New("plugin protocol version not supported")
80: 	}
81: 	p.pluginClient, err = newClientV2(p.descriptor, p.logger, rpcClient)
82: 	if err != nil {
83: 		p.state = pluginStateStartFail
84: 		return err
85: 	}
86: 
87: 	if p.pluginClient == nil {
88: 		p.state = pluginStateStartFail
89: 		return errors.New("no compatible plugin implementation found")
90: 	}
91: 
92: 	elevated, err := process.IsRunningWithElevatedPrivileges()
93: 	if err != nil {
94: 		p.logger.Debug("Error checking plugin process execution privilege", "error", err)
95: 	}
96: 	if elevated {
97: 		p.logger.Warn("Plugin process is running with elevated privileges. This is not recommended")
98: 	}
99: 
100: 	p.state = pluginStateStartSuccess
101: 	return nil
102: }
